Here's a complete example:

**XAML**
```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             x:Class="MyApp.Views.ItemsPage">

  <CollectionView ItemsSource="{Binding Items}"
                  SelectionMode="Single"
                  SelectedItem="{Binding SelectedItem}"
                  IsRefreshing="{Binding IsRefreshing}"
                  RemainingItemsThreshold="0">

    <!-- Pull-to-refresh via RefreshView wrapper -->
    <CollectionView.Behaviors>
      <!-- or wrap in RefreshView (see below) -->
    </CollectionView.Behaviors>

    <CollectionView.ItemTemplate>
      <DataTemplate>
        <VerticalStackLayout Padding="10">
          <Label Text="{Binding Name}" FontSize="18" />
          <Label Text="{Binding Description}" FontSize="14" TextColor="Gray" />
        </VerticalStackLayout>
      </DataTemplate>
    </CollectionView.ItemTemplate>
  </CollectionView>

</ContentPage>
```

Since `CollectionView` doesn't have built-in pull-to-refresh, wrap it in a `RefreshView`:

```xml
<RefreshView Command="{Binding RefreshCommand}"
             IsRefreshing="{Binding IsRefreshing}">

  <CollectionView ItemsSource="{Binding Items}"
                  SelectionMode="Single"
                  SelectedItem="{Binding SelectedItem}">
    <CollectionView.ItemTemplate>
      <DataTemplate>
        <VerticalStackLayout Padding="10">
          <Label Text="{Binding Name}" FontSize="18" />
          <Label Text="{Binding Description}" FontSize="14" TextColor="Gray" />
        </VerticalStackLayout>
      </DataTemplate>
    </CollectionView.ItemTemplate>
  </CollectionView>

</RefreshView>
```

**ViewModel**
```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;

    public ItemsViewModel(IApiService api, INavigationService nav)
    {
        _api = api;
        _nav = nav;
    }

    [ObservableProperty]
    private ObservableCollection<Item> _items = new();

    [ObservableProperty]
    private Item? _selectedItem;

    [ObservableProperty]
    private bool _isRefreshing;

    private readonly INavigationService _nav;

    // Fires when SelectedItem changes (CommunityToolkit.Mvvm source generator)
    partial void OnSelectedItemChanged(Item? value)
    {
        if (value is null) return;

        _nav.NavigateAsync(nameof(DetailPage), new Dictionary<string, object>
        {
            { "Item", value }
        });

        // Clear selection so the user can re-select the same item later
        SelectedItem = null;
    }

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            Items = new ObservableCollection<Item>(data);
        }
        finally
        {
            IsRefreshing = false; // stops the spinner
        }
    }
}
```

**Key bindings explained:**

| Binding | Purpose |
|---|---|
| `ItemsSource="{Binding Items}"` | Drives the list from an `ObservableCollection` |
| `SelectedItem="{Binding SelectedItem}"` | Two-way by default; triggers `OnSelectedItemChanged` for navigation |
| `SelectionMode="Single"` | Only one item selectable at a time |
| `Command="{Binding RefreshCommand}"` | `RefreshView` calls the generated `RelayCommand` on pull |
| `IsRefreshing="{Binding IsRefreshing}"` | Controls the refresh spinner; set `false` when done |

**Important details:**
- Reset `SelectedItem = null` after navigating so the same row can be tapped again.
- Always set `IsRefreshing = false` in a `finally` block to guarantee the spinner stops.
- This uses **CommunityToolkit.Mvvm** source generators (`[ObservableProperty]`, `[RelayCommand]`, `partial void OnSelectedItemChanged`).
